import java.util.Scanner;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter your name: ");
        String userInput = scanner.nextLine();

        // Properly encoding user input to prevent XSS
        String encodedUserInput = Encode.forHtml(userInput);

        String htmlResponse = "<h1>Welcome, " + encodedUserInput + "!</h1>";

        System.out.println("HTML response: " + htmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
